42→const RecapSection = ({ personal, group, streakCount, freezeAvailable }) => {
43→    const posts = personal?.posts_written || 0;
44→    const words = personal?.total_words || 0;
45→    const reactions = personal?.reactions_received || 0;
46→    const views = personal?.views_received || 0;
47→
48→    const tiles = [
49→        { icon: <PenIcon />, value: posts, label: 'posts', microCopy: getPostsCopy(posts) },
50→        { icon: <TypeIcon />, value: words, label: 'words', microCopy: getWordsCopy(words) },
51→        { icon: <HeartIcon />, value: reactions, label: 'reactions', microCopy: getReactionsCopy(reactions) },
52→        { icon: <EyeIcon />, value: views, label: 'views', microCopy: getViewsCopy(views) },
53→    ];
54→
55→    return (
56→        <div className="dashboard-recap-v2">
57→            <motion.p
58→                className="recap-encouragement"
59→                initial={{ opacity: 0 }}
60→                animate={{ opacity: 1 }}
61→                transition={{ duration: 0.3, delay: 0.05 }}
62→            >
63→                {getOverallEncouragement(personal, streakCount, freezeAvailable)}
64→            </motion.p>
65→
66→            <div className="recap-tiles-grid">
67→                {tiles.map((tile, i) => (
68→                    <StatTile key={tile.label} {...tile} index={i} />
69→                ))}
70→            </div>
71→
72→            <BestPostCard bestPost={personal?.best_post} />
73→
74→            <CommunityHighlights group={group} />
75→        </div>
76→    );
77→};
78→
79→export default RecapSection;
