 1→import React from 'react';
 2→import { motion } from 'framer-motion';
 3→import { useNavigate } from 'react-router-dom';
 4→import { useAuth } from '../../Context/useAuth';
 5→import { handleClickProfile } from '../../../helpers/handleClicks';
 6→
 7→const CommunityHighlights = ({ group }) => {
 8→    const navigate = useNavigate();
 9→    const { user } = useAuth();
10→    const clickProfile = handleClickProfile(navigate);
11→
12→    const mostActive = group?.most_active_writer;
13→    const mostReacted = group?.most_reacted_post;
14→
15→    if (!mostActive?.name && !mostReacted?.title) return null;
16→
17→    const goToProfile = (e) => {
18→        clickProfile(e, user?.id, mostActive.user_id, mostActive.username);
19→    };
20→
21→    const goToPost = () => {
22→        navigate(`/home/post/${mostReacted.journal_id}`);
23→    };
24→
25→    return (
26→        <motion.div
27→            className="recap-community"
28→            initial={{ opacity: 0 }}
29→            animate={{ opacity: 1 }}
30→            transition={{ duration: 0.3, delay: 0.55, ease: 'easeOut' }}
31→        >
32→            <span className="recap-community-label">This week on iskrib</span>
33→
34→            {mostActive && mostActive.name && (
35→                <div
36→                    className="recap-community-item recap-community-clickable"
37→                    onClick={goToProfile}
38→                    role="button"
39→                    tabIndex={0}
40→                    onKeyDown={(e) => e.key === 'Enter' && goToProfile(e)}
41→                >
42→                    <img
43→                        src={mostActive.avatar || '/assets/profile.jpg'}
44→                        alt={mostActive.name}
45→                        className="recap-community-avatar"
46→                    />
47→                    <span className="recap-community-text">
48→                        <strong>{mostActive.name}</strong> — {mostActive.post_count} posts
49→                    </span>
50→                </div>
51→            )}
52→
53→            {mostReacted && mostReacted.title && (
54→                <div
55→                    className="recap-community-item recap-community-clickable"
56→                    onClick={goToPost}
57→                    role="button"
58→                    tabIndex={0}
59→                    onKeyDown={(e) => e.key === 'Enter' && goToPost()}
60→                >
61→                    <img
62→                        src={mostReacted.author_avatar || '/assets/profile.jpg'}
63→                        alt={mostReacted.author_name}
64→                        className="recap-community-avatar"
65→                    />
66→                    <span className="recap-community-text">
67→                        <strong>{mostReacted.title}</strong> by {mostReacted.author_name} — {mostReacted.reaction_count || 0} reactions
68→                    </span>
69→                </div>
70→            )}
71→        </motion.div>
72→    );
73→};
74→
75→export default CommunityHighlights;
